import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.security.oauth2.common.exceptions.OAuth2Exception;
import org.springframework.web.bind.annotation.*;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.net.URI;
import java.util.*;

@SpringBootApplication
public class OauthServerApplication {
    public static void main(String[] args) {
        SpringApplication.run(OauthServerApplication.class, args);
    }
}

@RestController
public class AuthorizationCodeController {
    private final Map<String, String> authorizationCodes = new HashMap<>();
    private final List<String> registeredClientUrls = Arrays.asList("http://client1.example.com", "http://client2.example.com");

    @RequestMapping(value = "/oauth/authorize", method = RequestMethod.GET)
    public void authorize(@RequestParam String client_id, @RequestParam String redirect_uri, 
                          @RequestParam String response_type, HttpServletResponse response) throws IOException {
        if (!redirect_uri.startsWith(registeredClientUrls)) {
            throw new OAuth2Exception("Invalid Redirect URI");
        }
        
        // Generate authorization code and store it in the map with 10 minute expiration time
        String authCode = UUID.randomUUID().toString();
        Timer timer = new Timer();
        timer.schedule(new TimerTask() {
            @Override
            public void run() {
                authorizationCodes.remove(authCode);
            }
        }, 10 * 60 * 1000); // Time in milliseconds
        
        authorizationCodes.put(authCode, redirect_uri);
        
        response.sendRedirect(redirect_uri + "?code=" + authCode);
    }
}